return posts
  .filter((post) => Number(post.comments_count || 0) > 0)
  .map((post) => ({
    json: {
      post_id: post.id,
      post_permalink: post.permalink || '',
      post_caption: post.caption || '',
      post_timestamp: post.timestamp || null,
      comments_count: Number(post.comments_count || 0)
    }
  }));

function normalize(text) {
  return String(text || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase();
}

function cleanWords(text) {
  const value = normalize(text).replace(/[^a-z0-9\s]/g, ' ').trim();
  return value ? value.split(/\s+/) : [];
}

function isCommercialText(value) {
  return /(valor|preco|matricula|inscricao|link|comprar|agenda|consulta|curso|formacao|aasi|aura|palestra|orcamento)/.test(value);
}

function isRiskText(value) {
  return /(erro|errado|incorreto|falha|falhou|bug|problema|reclamacao|reclamar|ruim|pessimo|incompleto|incompleta|plagio|plagiado|copiado|enganoso|indevido|indevida|valor indevido|preco errado|link errado|link incorreto|nao funciona|nao funcionou|nao recebi|nao abre|quebrado|cancelamento|reembolso|devolucao|chargeback)/.test(value);
}

function isJiuJitsuTopic(value) {
  return /(jiu jitsu|jiujitsu|luta|tatame|faixa|treino|kimono|campeonato|graduacao)/.test(value);
}

function isFamilyTopic(value) {
  return /(familia|filho|filha|mae|pai|marido|esposa|minha filha|meu filho|minha mae|meu pai)/.test(value);
}

function isCtaEngagement(text, postCaption) {
  const value = normalize(text);
  const caption = normalize(postCaption);
  const words = cleanWords(text);
  const compact = words.join(' ');

  if (!compact) return false;
  if (/(crianca|criancas|mapa|perfeito|excelente|chapeu|potencial evocado|estado estavel)/.test(value)) return true;
  if (words.length <= 3 && compact.length >= 3 && caption.includes(compact)) return true;

  return words.length <= 2 && !isCommercialText(value);
}

function classifyTopic(text, postCaption) {
  const value = normalize(text);
  if (isRiskText(value)) return 'Risco / Reclamacao';
  if (/(valor|preco|matricula|inscricao|comprar|link)/.test(value)) return 'Preco / Inscricao';
  if (/(agenda|consulta|atendimento|avaliacao|aura|clinica)/.test(value)) return 'Consulta / Clinica';
  if (/(curso|formacao|imersao|aasi|aula)/.test(value)) return 'Curso / Formacao';
  if (/(palestra|evento|congresso|workshop)/.test(value)) return 'Palestra / Evento';
  if (/(zumbido|aparelho|perda auditiva|audicao|audiologia)/.test(value)) return 'Duvida tecnica';
  if (isJiuJitsuTopic(value)) return 'Jiu Jitsu';
  if (isFamilyTopic(value)) return 'Familia';
  if (isCtaEngagement(text, postCaption)) return 'Engajamento por CTA';
  if (/(amei|parabens|top|lindo|obrigada|obrigado|perfeito|excelente)/.test(value)) return 'Engajamento geral';
  return 'Sem tema definido';
}

function classifyPotential(text, postCaption) {
  const value = normalize(text);
  const topic = classifyTopic(text, postCaption);
  if (topic === 'Risco / Reclamacao') return 'alto';
  if (['Engajamento por CTA', 'Engajamento geral', 'Jiu Jitsu', 'Familia'].includes(topic)) return 'baixo';
  if (/(valor|preco|matricula|inscricao|link|comprar|agenda|consulta|palestra|orcamento)/.test(value)) return 'alto';
  if (/(curso|formacao|aasi|imersao|zumbido|interesse|quero|como funciona|aura|consulta|clinica|atendimento)/.test(value)) return 'medio';
  if (value.trim()) return 'baixo';
  return 'nao_classificado';
}

function suggestAction(text, postCaption) {
  const topic = classifyTopic(text, postCaption);
  if (topic === 'Risco / Reclamacao') return 'Priorizar resposta humana, corrigir link/valor se aplicavel e registrar acao tomada.';
  if (topic === 'Preco / Inscricao') return 'Responder com link, condicao e proximo passo de compra.';
  if (topic === 'Consulta / Clinica') return 'Responder com orientacao de atendimento clinico e confirmar necessidade.';
  if (topic === 'Curso / Formacao') return 'Responder com detalhes do curso e direcionar para inscricao/lista.';
  if (topic === 'Palestra / Evento') return 'Responder solicitando objetivo, data e formato do evento.';
  if (topic === 'Duvida tecnica') return 'Responder com acolhimento e direcionar para conteudo ou consulta.';
  if (topic === 'Jiu Jitsu') return 'Responder de forma leve e fortalecer conexao pessoal/comunidade.';
  if (topic === 'Familia') return 'Responder com acolhimento e manter relacionamento, sem tratar como lead direto.';
  if (topic === 'Engajamento por CTA') return 'Curtir ou responder curto; nao priorizar como lead comercial.';
  if (topic === 'Engajamento geral') return 'Agradecer e manter relacionamento.';
  return 'Analisar contexto antes de responder.';
}

const posts = $items('Preparar posts com comentarios');
const rows = [];

items.forEach((item, index) => {
  const post = posts[index]?.json || {};
  const comments = Array.isArray(item.json.data) ? item.json.data : [];

  comments.forEach((comment) => {
    const text = comment.text || '';
    const postCaption = post.post_caption || '';
    rows.push({
      json: {
        tenant_name: $env.PLATAFORMA_TENANT_NAME || 'Juliana Coutinho',
        account_name: $env.INSTAGRAM_ACCOUNT_NAME || 'Juliana Coutinho',
        username: $env.INSTAGRAM_USERNAME || 'fga.jucoutinho',
        source: 'post_comment',
        marketing_type: 'interacao_marketing',
        external_id: comment.id,
        profile_username: comment.username || comment.from?.username || comment.from?.id || null,
        profile_name: comment.from?.name || null,
        message_text: text,
        media_id: post.post_id || null,
        post_id: post.post_id || null,
        post_permalink: post.post_permalink || null,
        interaction_at: comment.timestamp || new Date().toISOString(),
        status: 'novo',
        potential: classifyPotential(text, postCaption),
        product_topic: classifyTopic(text, postCaption),
        next_action: suggestAction(text, postCaption),
        origem: 'n8n_instagram_comments_collector',
        raw_payload: {
          comment,
          post
        }
      }
    });
  });
});

return rows;

const validRows = items
  .map((item) => item.json)
  .filter((row) => row && row.external_id && row.source && row.interaction_at);

const batchSize = Number($env.INSTAGRAM_DIRECTS_BATCH_SIZE || 25);
const batches = [];

for (let index = 0; index < validRows.length; index += batchSize) {
  batches.push({
    json: {
      batch_number: Math.floor(index / batchSize) + 1,
      rows: validRows.slice(index, index + batchSize)
    }
  });
}

return batches;
